var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"구멍… 아니, 우물에서 갑자기 빛이 솟아났다고?","JPN":"穴……じゃなくて、井戸から突然光が溢れた？","ENG":"A light suddenly shot out of the hole… I mean, well?","TWN":"那個洞…不對，井裡突然發出光？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"갑자기가 아니다. 내가 도착하기 전부터 그렇게 빛나는 채였어.","JPN":"突然じゃない。私が着く前からそうなっていた。","ENG":"It wasn't sudden. It was like that before I even got there.","TWN":"不是突然。我到的時候就已經是那樣了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아쉽게도, 너희들이 오는 사이에 사라졌지만.","JPN":"残念ながら、お前たちが来る途中に消えてしまったが。","ENG":"Unfortunately, it vanished while you two were on your way.","TWN":"可惜，你們來的路上，光芒就消失了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사진은? 내가 준 폰으로 안 찍어뒀어?","JPN":"写真は？　私が渡した携帯で撮ってないの？","ENG":"What about a photo? Didn't you take one with the phone I gave you?","TWN":"照片呢？你沒用我給你的手機拍下來嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"보다시피 고장 났다. 전화를 걸자마자 바로 먹통이 되더군.","JPN":"見てのとおり壊れた。電話をかけた途端使えなくなった。","ENG":"As you can see, it's broken. The moment I tried to call, it just went dead.","TWN":"你看，壞掉了。打電話一接通，馬上就沒訊號了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"윽, 또야? 어쩐지 받기도 전에 끊어버리더라.","JPN":"げっ、また？　どうりで出る前に切れるわけだよ……","ENG":"Ugh, again? I knew something was up when it hung up before I could even pick up.","TWN":"呃，又這樣？難怪還沒接起來就斷了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 없는 틈에 먹비 한 방울 없이 장치가 작동하다니. 참으로 공교롭군.","JPN":"我らがいない間に墨雨もなしに装置が稼働するとは……あいにくだったな。","ENG":"So the device activated without a drop of Ink Rain while we were gone. What a coincidence.","TWN":"我們不在的時候，裝置竟然能在沒有墨雨的情況下運作。真是巧合。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러게. 하필 모두 자릴 비웠을 때 작동하는 건 좀 억울하네.","JPN":"ほんと。よりによって誰も居ない時に動いちゃうなんて、ちょっと悔しいよね。","ENG":"Right? Of all times, it had to be when no one was watching. That's just unfair.","TWN":"是啊。偏偏在我們都不在的時候啟動，也太讓人鬱悶了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래도 우물이 멀쩡히 작동한다는 사실을 확인한 건 좋은 소식일세.","JPN":"だが、井戸が正常に稼働すると確認できたのは収穫だ。","ENG":"Still, confirming the well can function properly is good news.","TWN":"不過，確認那口井能正常運作，是個好消息。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리 기억을 되짚다 보면 무엇이 우물을 가동한 원인인지 찾을 수 있을 지도 모르지.","JPN":"全員の記憶を辿ってみれば、井戸を稼働させた原因が何か突き止められるかもしれん。","ENG":"If we retrace our steps, we might be able to figure out what triggered it.","TWN":"如果我們回想一下，或許能找到是什麼原因啟動了那口井。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우린 이곳에서 침식체를 잡았어.","JPN":"私たちはここで侵食体を倒した。","ENG":"We took down a C.O. here.","TWN":"我們在這裡殺了侵蝕體。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"큰 녀석이니까, 그만큼 큰 이터니움을 품고 있었던 걸지도 모르지.","JPN":"デカいやつだったから、それに見合うだけのエタニウムを持っていたのかもしれない。","ENG":"It was a big one. Probably packed with a ton of Eternium.","TWN":"是個大塊頭，說不定它身上有大量的永恆之金。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우물이 부족한 동력원을 침식체한테 흡수해서 작동했다는 거야?","JPN":"井戸が、足りない動力源を侵食体から吸い取って動いたってこと？","ENG":"You think the well used the C.O. as a power source?","TWN":"你是說，那口井吸收了侵蝕體，補充了不足的動力才啟動的嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"가설은 많을수록 좋지. 다른 짚이는 점은 없나?","JPN":"仮説は多いほどいい。他に思い当たるところはないか？","ENG":"The more theories, the better. Anything else come to mind?","TWN":"假設越多越好。還有別的線索嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 뒤론 별일 없었다.","JPN":"その後は特に何も起こらなかった。","ENG":"Nothing worth mentioning after that.","TWN":"之後就沒什麼特別的事了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"침식체의 핵을 벤 당신은 피를 토하며 쓰러졌고, 그대로 도시의 병원으로 옮겨졌지.","JPN":"侵食体のコアを斬ったお前は血を吐いて倒れ、そのまま都市の病院に運ばれていった。","ENG":"After you struck the C.O.'s core, you collapsed coughing up blood. We rushed you to a hospital in the city.","TWN":"你斬了侵蝕體的核心後吐血倒下，然後被送到了城裡的醫院。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우리가 자릴 비운 하루 사이에 다른 어떤 일이 있었는진 몰라.","JPN":"私たちが居なかった1日の間に何があったかまでは分からない。","ENG":"Whatever happened while we were gone, no one knows.","TWN":"我們離開的這一天裡，還有沒有發生其他事，我們就不知道了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"그 누구도 지나간 일을 돌이키지 못해.","JPN":"過ぎたことは誰にも取り戻せないわ。","ENG":"No one can undo what's already passed.","TWN":"沒有任何人，能讓過去的事情重來。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"하지만 당신은 다르잖아. 특별한 피를 가졌으니까.","JPN":"でもあなたは違う。特別な血を持っているもの。","ENG":"But you're different. You carry a special bloodline.","TWN":"但你不同。你擁有特殊的血。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그런 거였군.","JPN":"……そういうことか。","ENG":"…So that's what it was.","TWN":"…原來如此。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"땅내림… 범… 그리고 먹비.","JPN":"チガカリ……虎……そして墨雨。","ENG":"Earthbound… the Tiger… and the Ink Rain.","TWN":"地脈之力…老虎…還有墨雨。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 모든 것과 연관성을 가진 하나가 이렇게 가까이에 있었는데도 몰랐다니.","JPN":"このすべてと関わりを持つものが、こうも近くに在ったにも関わらず気がつかないとは。","ENG":"Everything connected to them was right here under my nose, and I failed to see it.","TWN":"一個與所有這些都有關聯的存在，就在我身邊，我卻一直不知道。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아앗?! 갑자기 뭐하는 거야, 사부?","JPN":"ああ！？　いきなり何するの、師匠！","ENG":"Huh?! What are you doing, Master?!","TWN":"啊？！師父你突然幹什麼？！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜 자기 팔에 상처를 내는 건데?!","JPN":"なんで自分の腕に傷をつけるの！？","ENG":"Why would you cut your own arm?!","TWN":"為什麼要割自己的手臂？！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};